import{_ as r,c as e,o as i,ag as t}from"./chunks/framework.GdcW6lnn.js";const c=JSON.parse('{"title":"Що таке API?","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/something-api.md","filePath":"basics_api/something-api.md"}'),l={name:"basics_api/something-api.md"};function o(n,a,s,h,p,P){return i(),e("div",null,a[0]||(a[0]=[t('<h1 id="що-таке-api" tabindex="-1">Що таке API? <a class="header-anchor" href="#що-таке-api" aria-label="Permalink to “Що таке API?”">​</a></h1><h2 id="вступ" tabindex="-1">Вступ <a class="header-anchor" href="#вступ" aria-label="Permalink to “Вступ”">​</a></h2><p><strong>API (Application Programming Interface)</strong> — це інтерфейс програмування застосунків. Простими словами, це набір правил і протоколів, який дозволяє різним програмам взаємодіяти між собою.</p><p>API — це посередник між двома програмами, який дозволяє їм &quot;спілкуватися&quot;.</p><hr><h2 id="простии-приклад" tabindex="-1">Простий приклад <a class="header-anchor" href="#простии-приклад" aria-label="Permalink to “Простий приклад”">​</a></h2><p>Уявімо, що ви замовляєте їжу через мобільний додаток. Ви натискаєте на кнопку &quot;Замовити&quot;, і додаток відправляє ваш запит на сервер ресторану. Цей запит — це <strong>API-запит</strong>. Сервер обробляє його, готує відповідь і надсилає дані назад — наприклад, підтвердження замовлення або час доставки.</p><blockquote><p>Весь цей обмін інформацією відбувається через API.</p></blockquote><hr><h2 id="для-чого-потрібен-api" tabindex="-1">Для чого потрібен API? <a class="header-anchor" href="#для-чого-потрібен-api" aria-label="Permalink to “Для чого потрібен API?”">​</a></h2><ul><li>🔹 Для взаємодії між різними частинами програми.</li><li>🔹 Для інтеграції з іншими сервісами (наприклад, Google Maps або Stripe).</li><li>🔹 Для автоматизації процесів і побудови масштабованих систем.</li><li>🔹 Для відкриття функціоналу вашої програми іншим розробникам.</li></ul><hr><h2 id="як-виглядає-api" tabindex="-1">Як виглядає API? <a class="header-anchor" href="#як-виглядає-api" aria-label="Permalink to “Як виглядає API?”">​</a></h2><p>API зазвичай складається з:</p><ul><li><strong>Ендпоінтів (Endpoints)</strong> — це URL-адреси, куди надсилаються запити.</li><li><strong>Методів (Methods)</strong> — наприклад, GET, POST, PUT, DELETE.</li><li><strong>Параметрів запиту (Query/Body Parameters)</strong> — дані, які передаються в API.</li><li><strong>Формату відповіді</strong> — найчастіше JSON або XML.</li></ul><hr><h2 id="види-api" tabindex="-1">Види API <a class="header-anchor" href="#види-api" aria-label="Permalink to “Види API”">​</a></h2><ul><li><strong>REST API</strong> — найпопулярніший тип, заснований на HTTP-протоколі.</li><li><strong>SOAP API</strong> — більш формальний, використовує XML.</li><li><strong>GraphQL</strong> — гнучкий підхід, де клієнт сам визначає, які дані йому потрібні.</li><li><strong>gRPC</strong> — високопродуктивний двосторонній API, ідеальний для мікросервісів.</li></ul><hr><h2 id="висновок" tabindex="-1">Висновок <a class="header-anchor" href="#висновок" aria-label="Permalink to “Висновок”">​</a></h2><p>API — це основа сучасної розробки програмного забезпечення. Він дозволяє створювати модульні, гнучкі та масштабовані застосунки, які можуть легко взаємодіяти один з одним.</p><blockquote><p><strong>Коротко:</strong> API — це міст між двома системами, який дозволяє їм обмінюватися даними без &quot;ручного втручання&quot;.</p></blockquote><hr><h2 id="корисні-посилання" tabindex="-1">Корисні посилання <a class="header-anchor" href="#корисні-посилання" aria-label="Permalink to “Корисні посилання”">​</a></h2><ul><li><a href="https://uk.wikipedia.org/wiki/API" target="_blank" rel="noreferrer">Wikipedia: API (укр)</a></li><li><a href="https://www.postman.com/explore/" target="_blank" rel="noreferrer">What is an API? (Postman)</a></li><li><a href="https://www.redhat.com/en/topics/api/what-is-an-api-vs-sdk" target="_blank" rel="noreferrer">API vs SDK – пояснення від RedHat</a></li></ul>',25)]))}const g=r(l,[["render",o]]);export{c as __pageData,g as default};
